111	int nr_get_ssb_start_symbol(const NR_DL_FRAME_PARMS *fp, uint8_t i_ssb)
112	{
113	  int mu = fp->numerology_index;
114	  int symbol = 0;
115	  uint8_t n, n_temp;
116	  nr_ssb_type_e type = fp->ssb_type;
117	  int case_AC[2] = {2,8};
118	  int case_BD[4] = {4,8,16,20};
119	  int case_E[8] = {8, 12, 16, 20, 32, 36, 40, 44};
120	
121	  switch(mu) {
122	    case NR_MU_0: // case A
123	      n = i_ssb >> 1;
124	      symbol = case_AC[i_ssb % 2] + 14*n;
125	      break;
126	    case NR_MU_1:
127	      if (type == 1){ // case B
128	        n = i_ssb >> 2;
129	        symbol = case_BD[i_ssb % 4] + 28*n;
130	       }
131	       if (type == 2){ // case C
132	         n = i_ssb >> 1;
133	         symbol = case_AC[i_ssb % 2] + 14*n;
134	       }
135	       break;
136	     case NR_MU_3: // case D
137	       n_temp = i_ssb >> 2;
138	       n = n_temp + (n_temp >> 2);
139	       symbol = case_BD[i_ssb % 4] + 28*n;
140	       break;
141	     case NR_MU_4:  // case E
142	       n_temp = i_ssb >> 3;
143	       n = n_temp + (n_temp >> 2);
144	       symbol = case_E[i_ssb % 8] + 56*n;
145	       break;
146	     default:
147	       AssertFatal(0==1, "Invalid numerology index %d for the synchronization block\n", mu);
148	  }
149	
150	  return symbol;
151	}
